const sharp = require\('sharp'\);
const path = require\('path'\);

async function process\(\) {
  const input = path.join\('public', 'images', 'timeline', '1902.jpg'\);
  const output = path.join\('public', 'images', 'timeline', '1902.png'\);

  // Get image metadata first
  const meta = await sharp\(input\).metadata\(\);
  console.log\('Input:', meta.width, 'x', meta.height\);

  // Step 1: Read image, convert to greyscale, normalize contrast
  const processed = await sharp\(input\)
    .greyscale\(\)
    .normalize\(\)
    .modulate\({ brightness: 1.1 }\)
    .linear\(1.6, -60\)  // Boost contrast: darken text, lighten background
    .median\(3\)
    .sharpen\(\)
    .toBuffer\(\);

  // Step 2: Create alpha mask - light pixels become transparent, dark pixels stay
  // We threshold: pixels brighter than ~200 → transparent, darker → opaque
  const { data, info } = await sharp\(processed\)
    .raw\(\)
    .toBuffer\({ resolveWithObject: true }\);

  console.log\('Processed:', info.width, 'x', info.height, 'channels:', info.channels\);

  // Create RGBA buffer
  const rgba = Buffer.alloc\(info.width * info.height * 4\);
  for \(let i = 0; i < info.width * info.height; i++\) {
    const grey = data[i]; // single channel greyscale
    // Dark pixels \(text\) stay black and opaque, light pixels \(background\) become transparent
    if \(grey < 180\) {
      // Text - make it very dark/black
      const textValue = Math.max\(0, Math.min\(255, Math.round\(grey * 0.5\)\)\);
      rgba[i * 4 + 0] = textValue;
      rgba[i * 4 + 1] = textValue;
      rgba[i * 4 + 2] = textValue;
      rgba[i * 4 + 3] = 255; // fully opaque
    } else if \(grey < 210\) {
      // Transition zone - partial transparency for antialiasing
      const alpha = Math.round\(255 * \(210 - grey\) / 30\);
      const textValue = Math.max\(0, Math.min\(255, Math.round\(grey * 0.4\)\)\);
      rgba[i * 4 + 0] = textValue;
      rgba[i * 4 + 1] = textValue;
      rgba[i * 4 + 2] = textValue;
      rgba[i * 4 + 3] = alpha;
    } else {
      // Background - fully transparent
      rgba[i * 4 + 0] = 0;
      rgba[i * 4 + 1] = 0;
      rgba[i * 4 + 2] = 0;
      rgba[i * 4 + 3] = 0;
    }
  }

  // Step 3: Create transparent PNG with padding \(to fix cropped edges\)
  const padding = 40; // add 40px padding on each side
  await sharp\(rgba, {
    raw: {
      width: info.width,
      height: info.height,
      channels: 4
    }
  }\)
  .extend\({
    top: padding,
    bottom: padding,
    left: padding,
    right: padding,
    background: { r: 0, g: 0, b: 0, alpha: 0 }
  }\)
  .png\(\)
  .toFile\(output\);

  const outMeta = await sharp\(output\).metadata\(\);
  console.log\('Output:', outMeta.width, 'x', outMeta.height, 'format:', outMeta.format\);
  console.log\('Done! Saved to', output\);
}

process\(\).catch\(console.error\);
")

